//! Live provider benchmarks — requires running backends.
//!
//! Run with:
//!   cargo bench --bench live_providers
//!
//! Requires Ollama running on localhost:11434 with at least one model pulled.
//! Skips gracefully if Ollama is not reachable.

use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};

use hoosh::inference::{InferenceRequest, Message, Role};
use hoosh::provider::LlmProvider;

#[cfg(feature = "ollama")]
use hoosh::provider::ollama::OllamaProvider;

fn runtime() -> tokio::runtime::Runtime {
    tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build()
        .unwrap()
}

/// Returns (provider, first_model_id) if Ollama is reachable and has models.
#[cfg(feature = "ollama")]
fn ollama_if_available() -> Option<(OllamaProvider, String)> {
    let rt = runtime();
    let provider = OllamaProvider::new("http://127.0.0.1:11434");
    let healthy = rt.block_on(provider.health_check()).ok()?;
    if !healthy {
        return None;
    }
    let models = rt.block_on(provider.list_models()).ok()?;
    let first = models.first()?.id.clone();
    Some((provider, first))
}

#[cfg(feature = "ollama")]
fn bench_ollama_health(c: &mut Criterion) {
    let Some((provider, _)) = ollama_if_available() else {
        eprintln!("Skipping Ollama health bench — not reachable");
        return;
    };
    let rt = runtime();

    c.bench_function("ollama_health_check", |b| {
        b.iter(|| rt.block_on(provider.health_check()).unwrap())
    });
}

#[cfg(feature = "ollama")]
fn bench_ollama_list_models(c: &mut Criterion) {
    let Some((provider, _)) = ollama_if_available() else {
        eprintln!("Skipping Ollama list_models bench — not reachable");
        return;
    };
    let rt = runtime();

    c.bench_function("ollama_list_models", |b| {
        b.iter(|| rt.block_on(provider.list_models()).unwrap())
    });
}

#[cfg(feature = "ollama")]
fn bench_ollama_infer(c: &mut Criterion) {
    let Some((provider, model)) = ollama_if_available() else {
        eprintln!("Skipping Ollama infer bench — not reachable");
        return;
    };
    let rt = runtime();

    let mut group = c.benchmark_group("ollama_infer");
    // Inference is slow — reduce sample size and increase measurement time
    group.sample_size(10);
    group.measurement_time(std::time::Duration::from_secs(30));

    // Short prompt, constrained output
    let req_short = InferenceRequest {
        model: model.clone(),
        prompt: "Say hi.".into(),
        max_tokens: Some(5),
        temperature: Some(0.0),
        ..Default::default()
    };
    group.bench_with_input(
        BenchmarkId::new("short_prompt_5_tokens", &model),
        &req_short,
        |b, req| b.iter(|| rt.block_on(provider.infer(req)).unwrap()),
    );

    // Medium prompt, moderate output
    let req_medium = InferenceRequest {
        model: model.clone(),
        prompt: "Explain what Rust ownership is in two sentences.".into(),
        max_tokens: Some(50),
        temperature: Some(0.0),
        ..Default::default()
    };
    group.bench_with_input(
        BenchmarkId::new("medium_prompt_50_tokens", &model),
        &req_medium,
        |b, req| b.iter(|| rt.block_on(provider.infer(req)).unwrap()),
    );

    group.finish();
}

#[cfg(feature = "ollama")]
fn bench_ollama_infer_multiturn(c: &mut Criterion) {
    let Some((provider, model)) = ollama_if_available() else {
        eprintln!("Skipping Ollama multiturn bench — not reachable");
        return;
    };
    let rt = runtime();

    let mut group = c.benchmark_group("ollama_infer_multiturn");
    group.sample_size(10);
    group.measurement_time(std::time::Duration::from_secs(30));

    let req = InferenceRequest {
        model: model.clone(),
        messages: vec![
            Message {
                role: Role::System,
                content: "Answer in one sentence.".into(),
            },
            Message {
                role: Role::User,
                content: "What is Rust?".into(),
            },
            Message {
                role: Role::Assistant,
                content:
                    "Rust is a systems programming language focused on safety and performance."
                        .into(),
            },
            Message {
                role: Role::User,
                content: "What about its type system?".into(),
            },
        ],
        max_tokens: Some(30),
        temperature: Some(0.0),
        ..Default::default()
    };

    group.bench_with_input(
        BenchmarkId::new("4_message_history", &model),
        &req,
        |b, req| b.iter(|| rt.block_on(provider.infer(req)).unwrap()),
    );

    group.finish();
}

#[cfg(feature = "ollama")]
fn bench_ollama_stream_throughput(c: &mut Criterion) {
    let Some((provider, model)) = ollama_if_available() else {
        eprintln!("Skipping Ollama stream bench — not reachable");
        return;
    };
    let rt = runtime();

    let mut group = c.benchmark_group("ollama_stream");
    group.sample_size(10);
    group.measurement_time(std::time::Duration::from_secs(30));

    let req = InferenceRequest {
        model: model.clone(),
        prompt: "Count from 1 to 10.".into(),
        max_tokens: Some(50),
        temperature: Some(0.0),
        stream: true,
        ..Default::default()
    };

    group.bench_with_input(
        BenchmarkId::new("stream_50_tokens", &model),
        &req,
        |b, req| {
            b.iter(|| {
                rt.block_on(async {
                    let mut rx = provider.infer_stream(req.clone()).await.unwrap();
                    let mut count = 0;
                    while let Some(result) = rx.recv().await {
                        result.unwrap();
                        count += 1;
                    }
                    count
                })
            })
        },
    );

    group.finish();
}

// ---------------------------------------------------------------------------
// Hardware detection benchmarks (ai-hwaccel)
// ---------------------------------------------------------------------------

#[cfg(feature = "hwaccel")]
fn bench_hwaccel_detect(c: &mut Criterion) {
    use hoosh::hardware::HardwareManager;

    c.bench_function("hwaccel_detect", |b| b.iter(|| HardwareManager::detect()));
}

#[cfg(feature = "hwaccel")]
fn bench_hwaccel_summary(c: &mut Criterion) {
    use hoosh::hardware::HardwareManager;

    let hw = HardwareManager::detect();
    c.bench_function("hwaccel_summary", |b| b.iter(|| hw.summary()));
}

#[cfg(feature = "hwaccel")]
fn bench_hwaccel_recommend_placement(c: &mut Criterion) {
    use hoosh::hardware::HardwareManager;

    let hw = HardwareManager::detect();
    let providers = vec![
        "ollama".to_string(),
        "llamacpp".to_string(),
        "localai".to_string(),
    ];

    let mut group = c.benchmark_group("hwaccel_recommend_placement");

    // Small model (1B params)
    group.bench_function("1b_params", |b| {
        b.iter(|| hw.recommend_placement(1_000_000_000, &providers))
    });

    // Medium model (7B params)
    group.bench_function("7b_params", |b| {
        b.iter(|| hw.recommend_placement(7_000_000_000, &providers))
    });

    // Large model (70B params)
    group.bench_function("70b_params", |b| {
        b.iter(|| hw.recommend_placement(70_000_000_000, &providers))
    });

    group.finish();
}

// ---------------------------------------------------------------------------
// Criterion group assembly
// ---------------------------------------------------------------------------

#[cfg(all(feature = "ollama", feature = "hwaccel"))]
criterion_group!(
    benches,
    bench_ollama_health,
    bench_ollama_list_models,
    bench_ollama_infer,
    bench_ollama_infer_multiturn,
    bench_ollama_stream_throughput,
    bench_hwaccel_detect,
    bench_hwaccel_summary,
    bench_hwaccel_recommend_placement,
);

#[cfg(all(feature = "ollama", not(feature = "hwaccel")))]
criterion_group!(
    benches,
    bench_ollama_health,
    bench_ollama_list_models,
    bench_ollama_infer,
    bench_ollama_infer_multiturn,
    bench_ollama_stream_throughput,
);

#[cfg(all(not(feature = "ollama"), feature = "hwaccel"))]
criterion_group!(
    benches,
    bench_hwaccel_detect,
    bench_hwaccel_summary,
    bench_hwaccel_recommend_placement,
);

#[cfg(not(any(feature = "ollama", feature = "hwaccel")))]
fn no_op(_c: &mut Criterion) {
    eprintln!("No live features enabled — skipping live benchmarks");
}

#[cfg(not(any(feature = "ollama", feature = "hwaccel")))]
criterion_group!(benches, no_op);

criterion_main!(benches);

use criterion::{Criterion, criterion_group, criterion_main};

use hoosh::inference::{InferenceRequest, Message, Role};
use hoosh::provider::openai_compat::OpenAiCompatibleProvider;
use hoosh::provider::{ProviderRegistry, ProviderType};
use hoosh::router::ProviderRoute;

// ---------------------------------------------------------------------------
// ProviderRegistry benchmarks
// ---------------------------------------------------------------------------

fn make_routes(n: usize) -> Vec<ProviderRoute> {
    let types = [
        ProviderType::Ollama,
        ProviderType::LlamaCpp,
        ProviderType::LmStudio,
        ProviderType::LocalAi,
        ProviderType::Synapse,
    ];
    (0..n)
        .map(|i| ProviderRoute {
            provider: types[i % types.len()],
            priority: i as u32,
            model_patterns: vec![format!("model-{}*", i)],
            enabled: true,
            base_url: format!("http://provider-{}:{}", i, 8080 + i),
            api_key: None,
            max_tokens_limit: None,
        })
        .collect()
}

fn bench_registry_register(c: &mut Criterion) {
    let routes = make_routes(20);
    c.bench_function("registry_register_20_routes", |b| {
        b.iter(|| {
            let mut registry = ProviderRegistry::new();
            for route in &routes {
                registry.register_from_route(route);
            }
            registry
        })
    });
}

fn bench_registry_lookup(c: &mut Criterion) {
    let routes = make_routes(20);
    let mut registry = ProviderRegistry::new();
    for route in &routes {
        registry.register_from_route(route);
    }

    c.bench_function("registry_lookup_hit", |b| {
        b.iter(|| registry.get(ProviderType::Ollama, "http://provider-0:8080"))
    });

    c.bench_function("registry_lookup_miss", |b| {
        b.iter(|| registry.get(ProviderType::Whisper, "http://nonexistent:9999"))
    });
}

// ---------------------------------------------------------------------------
// build_chat_body (via OpenAiCompatibleProvider construction + body building)
// ---------------------------------------------------------------------------

fn bench_provider_construction(c: &mut Criterion) {
    c.bench_function("openai_compat_new", |b| {
        b.iter(|| {
            OpenAiCompatibleProvider::new("http://localhost:8080", None, ProviderType::LlamaCpp)
        })
    });

    c.bench_function("openai_compat_new_with_key", |b| {
        b.iter(|| {
            OpenAiCompatibleProvider::new(
                "http://localhost:8080/",
                Some("sk-test-key-12345".into()),
                ProviderType::OpenAi,
            )
        })
    });
}

fn bench_inference_request_construction(c: &mut Criterion) {
    c.bench_function("inference_request_simple", |b| {
        b.iter(|| InferenceRequest {
            model: "llama3".into(),
            prompt: "Explain Rust ownership.".into(),
            ..Default::default()
        })
    });

    c.bench_function("inference_request_with_messages", |b| {
        b.iter(|| InferenceRequest {
            model: "llama3".into(),
            messages: vec![
                Message {
                    role: Role::System,
                    content: "You are a helpful assistant.".into(),
                },
                Message {
                    role: Role::User,
                    content: "Explain Rust ownership.".into(),
                },
                Message {
                    role: Role::Assistant,
                    content: "Rust uses an ownership model...".into(),
                },
                Message {
                    role: Role::User,
                    content: "Give me an example.".into(),
                },
            ],
            temperature: Some(0.7),
            max_tokens: Some(1024),
            ..Default::default()
        })
    });
}

// ---------------------------------------------------------------------------
// Serde serialization (request → JSON, as providers do internally)
// ---------------------------------------------------------------------------

fn bench_request_serialization(c: &mut Criterion) {
    let simple = InferenceRequest {
        model: "llama3".into(),
        prompt: "Hello world".into(),
        ..Default::default()
    };

    let complex = InferenceRequest {
        model: "llama3".into(),
        messages: (0..10)
            .map(|i| Message {
                role: if i % 2 == 0 {
                    Role::User
                } else {
                    Role::Assistant
                },
                content: format!("Message number {} with some content to serialize.", i),
            })
            .collect(),
        temperature: Some(0.7),
        max_tokens: Some(2048),
        top_p: Some(0.9),
        stream: true,
        ..Default::default()
    };

    c.bench_function("serialize_simple_request", |b| {
        b.iter(|| serde_json::to_string(&simple).unwrap())
    });

    c.bench_function("serialize_10_message_request", |b| {
        b.iter(|| serde_json::to_string(&complex).unwrap())
    });
}

criterion_group!(
    benches,
    bench_registry_register,
    bench_registry_lookup,
    bench_provider_construction,
    bench_inference_request_construction,
    bench_request_serialization,
);
criterion_main!(benches);

use criterion::{Criterion, criterion_group, criterion_main};

use hoosh::provider::ProviderType;
use hoosh::router::{ProviderRoute, Router, RoutingStrategy};

fn make_routes(n: usize) -> Vec<ProviderRoute> {
    (0..n)
        .map(|i| ProviderRoute {
            provider: if i % 2 == 0 {
                ProviderType::Ollama
            } else {
                ProviderType::OpenAi
            },
            priority: i as u32,
            model_patterns: vec![format!("model-{}*", i)],
            enabled: true,
            base_url: format!("http://provider-{}", i),
            api_key: None,
            max_tokens_limit: None,
        })
        .collect()
}

fn bench_routing(c: &mut Criterion) {
    let routes = make_routes(20);
    let router = Router::new(routes, RoutingStrategy::Priority);

    c.bench_function("route_select_20_providers", |b| {
        b.iter(|| router.select("model-15-large"))
    });
}

fn bench_routing_round_robin(c: &mut Criterion) {
    let routes = make_routes(10);
    let router = Router::new(routes, RoutingStrategy::RoundRobin);

    c.bench_function("route_round_robin_10", |b| {
        b.iter(|| router.select("model-5-base"))
    });
}

criterion_group!(benches, bench_routing, bench_routing_round_robin);
criterion_main!(benches);

//! Token budget management: per-agent and per-pool token accounting.

use std::collections::HashMap;

use serde::{Deserialize, Serialize};

/// A named token pool with a capacity limit.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TokenPool {
    /// Pool name (e.g. "default", "agent-123", "batch-jobs").
    pub name: String,
    /// Maximum tokens allowed in this pool.
    pub capacity: u64,
    /// Tokens consumed so far.
    pub used: u64,
    /// Tokens currently reserved (pending completion).
    pub reserved: u64,
}

impl TokenPool {
    /// Create a new pool with the given capacity.
    pub fn new(name: impl Into<String>, capacity: u64) -> Self {
        Self {
            name: name.into(),
            capacity,
            used: 0,
            reserved: 0,
        }
    }

    /// Available tokens (capacity - used - reserved).
    pub fn available(&self) -> u64 {
        self.capacity
            .saturating_sub(self.used.saturating_add(self.reserved))
    }

    /// Whether the pool can accommodate `tokens` more.
    pub fn can_reserve(&self, tokens: u64) -> bool {
        self.available() >= tokens
    }

    /// Reserve tokens (before inference).
    pub fn reserve(&mut self, tokens: u64) -> bool {
        if !self.can_reserve(tokens) {
            return false;
        }
        self.reserved += tokens;
        true
    }

    /// Commit reserved tokens as used (after inference completes).
    pub fn commit(&mut self, reserved: u64, actual: u64) {
        self.reserved = self.reserved.saturating_sub(reserved);
        self.used = self.used.saturating_add(actual);
    }

    /// Release reserved tokens without using them (on failure/cancel).
    pub fn release(&mut self, tokens: u64) {
        self.reserved = self.reserved.saturating_sub(tokens);
    }

    /// Utilisation ratio (0.0–1.0).
    pub fn utilization(&self) -> f64 {
        if self.capacity == 0 {
            return 0.0;
        }
        self.used as f64 / self.capacity as f64
    }
}

/// Token budget manager: tracks multiple named pools.
pub struct TokenBudget {
    pools: HashMap<String, TokenPool>,
}

impl TokenBudget {
    /// Create a new budget manager.
    pub fn new() -> Self {
        Self {
            pools: HashMap::new(),
        }
    }

    /// Add or replace a pool.
    pub fn add_pool(&mut self, pool: TokenPool) {
        self.pools.insert(pool.name.clone(), pool);
    }

    /// Get a pool by name.
    pub fn get_pool(&self, name: &str) -> Option<&TokenPool> {
        self.pools.get(name)
    }

    /// Get a mutable pool by name.
    pub fn get_pool_mut(&mut self, name: &str) -> Option<&mut TokenPool> {
        self.pools.get_mut(name)
    }

    /// All pools.
    pub fn pools(&self) -> &HashMap<String, TokenPool> {
        &self.pools
    }

    /// Check if a pool can accommodate a request.
    pub fn check(&self, pool_name: &str, tokens: u64) -> bool {
        self.pools
            .get(pool_name)
            .map(|p| p.can_reserve(tokens))
            .unwrap_or(false)
    }

    /// Reserve tokens in a pool.
    pub fn reserve(&mut self, pool_name: &str, tokens: u64) -> bool {
        self.pools
            .get_mut(pool_name)
            .map(|p| p.reserve(tokens))
            .unwrap_or(false)
    }

    /// Report actual usage and release the reservation.
    pub fn report(&mut self, pool_name: &str, reserved: u64, actual: u64) {
        if let Some(pool) = self.pools.get_mut(pool_name) {
            pool.commit(reserved, actual);
        }
    }
}

impl Default for TokenBudget {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn pool_basic() {
        let mut pool = TokenPool::new("test", 1000);
        assert_eq!(pool.available(), 1000);
        assert!(pool.reserve(400));
        assert_eq!(pool.available(), 600);
        pool.commit(400, 350);
        assert_eq!(pool.used, 350);
        assert_eq!(pool.reserved, 0);
        assert_eq!(pool.available(), 650);
    }

    #[test]
    fn pool_over_budget() {
        let pool = TokenPool::new("test", 100);
        assert!(!pool.can_reserve(200));
    }

    #[test]
    fn pool_release() {
        let mut pool = TokenPool::new("test", 1000);
        pool.reserve(500);
        pool.release(500);
        assert_eq!(pool.reserved, 0);
        assert_eq!(pool.available(), 1000);
    }

    #[test]
    fn pool_utilization() {
        let mut pool = TokenPool::new("test", 1000);
        pool.used = 750;
        assert!((pool.utilization() - 0.75).abs() < f64::EPSILON);
    }

    #[test]
    fn budget_multi_pool() {
        let mut budget = TokenBudget::new();
        budget.add_pool(TokenPool::new("default", 10000));
        budget.add_pool(TokenPool::new("agent-1", 5000));

        assert!(budget.check("default", 8000));
        assert!(!budget.check("agent-1", 8000));
        assert!(!budget.check("nonexistent", 1));
    }

    #[test]
    fn budget_reserve_report() {
        let mut budget = TokenBudget::new();
        budget.add_pool(TokenPool::new("pool", 1000));
        assert!(budget.reserve("pool", 500));
        budget.report("pool", 500, 420);
        let pool = budget.get_pool("pool").unwrap();
        assert_eq!(pool.used, 420);
        assert_eq!(pool.reserved, 0);
    }
}

//! Response caching for inference results.

use std::sync::Arc;
use std::time::{Duration, Instant};

use dashmap::DashMap;
use serde::{Deserialize, Serialize};

/// Configuration for the response cache.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CacheConfig {
    /// Maximum number of cached entries.
    pub max_entries: usize,
    /// Time-to-live for cached entries.
    pub ttl_secs: u64,
    /// Whether caching is enabled.
    pub enabled: bool,
}

impl Default for CacheConfig {
    fn default() -> Self {
        Self {
            max_entries: 1000,
            ttl_secs: 300,
            enabled: true,
        }
    }
}

struct CacheEntry {
    value: Arc<String>,
    created: Instant,
    ttl: Duration,
}

impl CacheEntry {
    fn is_expired(&self) -> bool {
        self.created.elapsed() > self.ttl
    }
}

/// Build a cache key from model + messages hash to avoid collisions.
pub fn cache_key(model: &str, messages: &[crate::inference::Message]) -> String {
    use std::hash::{Hash, Hasher};
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    model.hash(&mut hasher);
    for m in messages {
        std::mem::discriminant(&m.role).hash(&mut hasher);
        m.content.hash(&mut hasher);
    }
    format!("{}:{:016x}", model, hasher.finish())
}

/// Thread-safe response cache with TTL eviction.
pub struct ResponseCache {
    entries: DashMap<String, CacheEntry>,
    config: CacheConfig,
}

impl ResponseCache {
    /// Create a new cache with the given configuration.
    pub fn new(config: CacheConfig) -> Self {
        Self {
            entries: DashMap::new(),
            config,
        }
    }

    /// Look up a cached response by key.
    pub fn get(&self, key: &str) -> Option<Arc<String>> {
        if !self.config.enabled {
            return None;
        }
        let entry = self.entries.get(key)?;
        if entry.is_expired() {
            drop(entry);
            self.entries.remove(key);
            return None;
        }
        Some(entry.value.clone())
    }

    /// Insert a response into the cache.
    pub fn insert(&self, key: String, value: String) {
        if !self.config.enabled {
            return;
        }
        // Evict if at capacity
        if self.entries.len() >= self.config.max_entries {
            self.evict_expired();
            // If still at capacity after evicting expired, drop oldest entries
            if self.entries.len() >= self.config.max_entries {
                let to_remove = self.entries.len() - self.config.max_entries + 1;
                let keys: Vec<String> = self
                    .entries
                    .iter()
                    .take(to_remove)
                    .map(|e| e.key().clone())
                    .collect();
                for key in keys {
                    self.entries.remove(&key);
                }
            }
        }
        self.entries.insert(
            key,
            CacheEntry {
                value: Arc::new(value),
                created: Instant::now(),
                ttl: Duration::from_secs(self.config.ttl_secs),
            },
        );
    }

    /// Number of entries in the cache.
    pub fn len(&self) -> usize {
        self.entries.len()
    }

    /// Whether the cache is empty.
    pub fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }

    /// Clear all entries.
    pub fn clear(&self) {
        self.entries.clear();
    }

    /// Remove expired entries.
    fn evict_expired(&self) {
        self.entries.retain(|_, entry| !entry.is_expired());
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cache_insert_get() {
        let cache = ResponseCache::new(CacheConfig::default());
        cache.insert("key1".into(), "value1".into());
        assert_eq!(cache.get("key1").as_deref(), Some(&"value1".to_string()));
        assert_eq!(cache.len(), 1);
    }

    #[test]
    fn cache_miss() {
        let cache = ResponseCache::new(CacheConfig::default());
        assert!(cache.get("nonexistent").is_none());
    }

    #[test]
    fn cache_disabled() {
        let cache = ResponseCache::new(CacheConfig {
            enabled: false,
            ..Default::default()
        });
        cache.insert("key".into(), "value".into());
        assert!(cache.get("key").is_none());
        assert!(cache.is_empty());
    }

    #[test]
    fn cache_clear() {
        let cache = ResponseCache::new(CacheConfig::default());
        cache.insert("a".into(), "1".into());
        cache.insert("b".into(), "2".into());
        assert_eq!(cache.len(), 2);
        cache.clear();
        assert!(cache.is_empty());
    }

    #[test]
    fn config_default() {
        let cfg = CacheConfig::default();
        assert_eq!(cfg.max_entries, 1000);
        assert_eq!(cfg.ttl_secs, 300);
        assert!(cfg.enabled);
    }

    #[test]
    fn cache_eviction_at_capacity() {
        let cache = ResponseCache::new(CacheConfig {
            max_entries: 3,
            ttl_secs: 300,
            enabled: true,
        });
        cache.insert("a".into(), "1".into());
        cache.insert("b".into(), "2".into());
        cache.insert("c".into(), "3".into());
        assert_eq!(cache.len(), 3);
        // This should trigger eviction
        cache.insert("d".into(), "4".into());
        assert!(cache.len() <= 3);
        // New entry should be present
        assert!(cache.get("d").is_some());
    }

    #[test]
    fn cache_ttl_expiry() {
        let cache = ResponseCache::new(CacheConfig {
            max_entries: 100,
            ttl_secs: 0, // expire immediately
            enabled: true,
        });
        cache.insert("key".into(), "value".into());
        // Entry should be expired
        std::thread::sleep(std::time::Duration::from_millis(10));
        assert!(cache.get("key").is_none());
    }

    #[test]
    fn cache_key_different_models() {
        use crate::inference::{Message, Role};
        let msgs = vec![Message {
            role: Role::User,
            content: "hello".into(),
        }];
        let k1 = super::cache_key("llama3", &msgs);
        let k2 = super::cache_key("gpt-4", &msgs);
        assert_ne!(k1, k2);
        assert!(k1.starts_with("llama3:"));
        assert!(k2.starts_with("gpt-4:"));
    }

    #[test]
    fn cache_key_different_messages() {
        use crate::inference::{Message, Role};
        let msgs1 = vec![Message {
            role: Role::User,
            content: "hello".into(),
        }];
        let msgs2 = vec![Message {
            role: Role::User,
            content: "world".into(),
        }];
        let k1 = super::cache_key("model", &msgs1);
        let k2 = super::cache_key("model", &msgs2);
        assert_ne!(k1, k2);
    }

    #[test]
    fn cache_key_same_request() {
        use crate::inference::{Message, Role};
        let msgs = vec![Message {
            role: Role::User,
            content: "hello".into(),
        }];
        let k1 = super::cache_key("model", &msgs);
        let k2 = super::cache_key("model", &msgs);
        assert_eq!(k1, k2);
    }

    #[test]
    fn evict_expired_removes_stale() {
        let cache = ResponseCache::new(CacheConfig {
            max_entries: 100,
            ttl_secs: 0,
            enabled: true,
        });
        cache.insert("a".into(), "1".into());
        cache.insert("b".into(), "2".into());
        std::thread::sleep(std::time::Duration::from_millis(10));
        cache.evict_expired();
        assert!(cache.is_empty());
    }
}

//! HTTP client for talking to a hoosh server.
//!
//! This is what downstream crates (tarang, daimon, consumer apps) use to
//! call hoosh over the network. OpenAI-compatible API.

use serde::Deserialize;
use tokio::sync::mpsc;

use crate::error::{HooshError, Result};
use crate::inference::{InferenceRequest, InferenceResponse, ModelInfo, Role, TokenUsage};

/// HTTP client for the hoosh inference gateway.
#[derive(Debug, Clone)]
pub struct HooshClient {
    base_url: String,
    client: reqwest::Client,
}

/// Build an OpenAI-compatible chat body from an InferenceRequest.
fn to_chat_body(request: &InferenceRequest) -> serde_json::Value {
    let messages: Vec<serde_json::Value> = if request.messages.is_empty() {
        let mut msgs = Vec::new();
        if let Some(sys) = &request.system {
            msgs.push(serde_json::json!({"role": "system", "content": sys}));
        }
        msgs.push(serde_json::json!({"role": "user", "content": request.prompt}));
        msgs
    } else {
        request
            .messages
            .iter()
            .map(|m| {
                let role = match m.role {
                    Role::System => "system",
                    Role::User => "user",
                    Role::Assistant => "assistant",
                };
                serde_json::json!({"role": role, "content": m.content})
            })
            .collect()
    };

    let mut body = serde_json::json!({
        "model": request.model,
        "messages": messages,
        "stream": request.stream,
    });
    if let Some(max) = request.max_tokens {
        body["max_tokens"] = serde_json::json!(max);
    }
    if let Some(temp) = request.temperature {
        body["temperature"] = serde_json::json!(temp);
    }
    if let Some(tp) = request.top_p {
        body["top_p"] = serde_json::json!(tp);
    }
    body
}

#[derive(Deserialize)]
struct ChatCompletionResp {
    model: Option<String>,
    choices: Vec<ChatChoice>,
    usage: Option<ChatUsageResp>,
}

#[derive(Deserialize)]
struct ChatChoice {
    message: ChatMsg,
}

#[derive(Deserialize)]
struct ChatMsg {
    content: Option<String>,
}

#[derive(Deserialize)]
struct ChatUsageResp {
    prompt_tokens: Option<u32>,
    completion_tokens: Option<u32>,
    total_tokens: Option<u32>,
}

#[derive(Deserialize)]
struct StreamChunk {
    choices: Vec<StreamChoice>,
}

#[derive(Deserialize)]
struct StreamChoice {
    delta: StreamDelta,
}

#[derive(Deserialize)]
struct StreamDelta {
    content: Option<String>,
}

#[derive(Deserialize)]
struct ModelsResp {
    data: Vec<ModelObj>,
}

#[derive(Deserialize)]
struct ModelObj {
    id: String,
    owned_by: Option<String>,
}

impl HooshClient {
    /// Create a new client pointing at the given hoosh server.
    pub fn new(base_url: impl Into<String>) -> Self {
        Self {
            base_url: base_url.into().trim_end_matches('/').to_string(),
            client: reqwest::Client::new(),
        }
    }

    /// Run inference via the hoosh server.
    pub async fn infer(&self, request: &InferenceRequest) -> Result<InferenceResponse> {
        let url = format!("{}/v1/chat/completions", self.base_url);
        let body = to_chat_body(&InferenceRequest {
            stream: false,
            ..request.clone()
        });

        let resp = self
            .client
            .post(&url)
            .json(&body)
            .send()
            .await?
            .error_for_status()
            .map_err(|e| HooshError::Provider(e.to_string()))?;

        let parsed: ChatCompletionResp = resp
            .json()
            .await
            .map_err(|e| HooshError::Provider(e.to_string()))?;

        let text = parsed
            .choices
            .first()
            .and_then(|c| c.message.content.clone())
            .unwrap_or_default();

        let usage = parsed.usage.as_ref();
        Ok(InferenceResponse {
            text,
            model: parsed.model.unwrap_or_else(|| request.model.clone()),
            usage: TokenUsage {
                prompt_tokens: usage.and_then(|u| u.prompt_tokens).unwrap_or(0),
                completion_tokens: usage.and_then(|u| u.completion_tokens).unwrap_or(0),
                total_tokens: usage.and_then(|u| u.total_tokens).unwrap_or(0),
            },
            provider: "hoosh".into(),
            latency_ms: 0,
        })
    }

    /// Stream inference results token by token.
    pub async fn infer_stream(
        &self,
        request: &InferenceRequest,
    ) -> Result<mpsc::Receiver<std::result::Result<String, HooshError>>> {
        let url = format!("{}/v1/chat/completions", self.base_url);
        let body = to_chat_body(&InferenceRequest {
            stream: true,
            ..request.clone()
        });

        let resp = self
            .client
            .post(&url)
            .json(&body)
            .send()
            .await?
            .error_for_status()
            .map_err(|e| HooshError::Provider(e.to_string()))?;

        if let Some(ct) = resp.headers().get("content-type") {
            let ct_str = ct.to_str().unwrap_or("");
            if !ct_str.contains("text/event-stream") && !ct_str.contains("application/json") {
                return Err(HooshError::Provider(format!(
                    "expected SSE stream, got Content-Type: {ct_str}"
                )));
            }
        }

        let (tx, rx) = mpsc::channel(256);

        tokio::spawn(async move {
            use futures::StreamExt;
            let mut stream = resp.bytes_stream();
            let mut buf = String::new();

            while let Some(chunk) = stream.next().await {
                let chunk = match chunk {
                    Ok(c) => c,
                    Err(e) => {
                        let _ = tx.send(Err(HooshError::Provider(e.to_string()))).await;
                        return;
                    }
                };
                if buf.len() + chunk.len() > 1024 * 1024 {
                    let _ = tx
                        .send(Err(HooshError::Provider(
                            "SSE line exceeded 1MB limit".into(),
                        )))
                        .await;
                    return;
                }
                buf.push_str(&String::from_utf8_lossy(&chunk));

                while let Some(pos) = buf.find('\n') {
                    let line = buf[..pos].trim().to_string();
                    buf = buf[pos + 1..].to_string();

                    if line.is_empty() || line.starts_with(':') {
                        continue;
                    }
                    let data = if let Some(d) = line.strip_prefix("data: ") {
                        d.trim()
                    } else if let Some(d) = line.strip_prefix("data:") {
                        d.trim()
                    } else {
                        continue;
                    };
                    if data == "[DONE]" {
                        return;
                    }
                    if let Ok(chunk) = serde_json::from_str::<StreamChunk>(data) {
                        for choice in &chunk.choices {
                            if let Some(content) = &choice.delta.content
                                && !content.is_empty()
                                && tx.send(Ok(content.clone())).await.is_err()
                            {
                                return;
                            }
                        }
                    }
                }
            }
        });

        Ok(rx)
    }

    /// List available models.
    pub async fn list_models(&self) -> Result<Vec<ModelInfo>> {
        let url = format!("{}/v1/models", self.base_url);
        let resp = self
            .client
            .get(&url)
            .send()
            .await?
            .error_for_status()
            .map_err(|e| HooshError::Provider(e.to_string()))?;

        let parsed: ModelsResp = resp
            .json()
            .await
            .map_err(|e| HooshError::Provider(e.to_string()))?;

        Ok(parsed
            .data
            .into_iter()
            .map(|m| ModelInfo {
                id: m.id.clone(),
                name: m.id,
                provider: m.owned_by.unwrap_or_else(|| "hoosh".into()),
                parameters: None,
                context_length: None,
                available: true,
            })
            .collect())
    }

    /// Health check.
    pub async fn health(&self) -> Result<bool> {
        let url = format!("{}/v1/health", self.base_url);
        match self.client.get(&url).send().await {
            Ok(resp) => Ok(resp.status().is_success()),
            Err(_) => Ok(false),
        }
    }

    /// Base URL of the hoosh server.
    pub fn base_url(&self) -> &str {
        &self.base_url
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn client_creation() {
        let client = HooshClient::new("http://localhost:8088");
        assert_eq!(client.base_url(), "http://localhost:8088");
    }

    #[test]
    fn client_strips_trailing_slash() {
        let client = HooshClient::new("http://localhost:8088/");
        assert_eq!(client.base_url(), "http://localhost:8088");
    }
}

//! Configuration file loading for hoosh.
//!
//! Loads `hoosh.toml` from the current directory or a specified path.
//! Environment variables in API keys are resolved at load time.

use std::path::Path;

use serde::Deserialize;

use crate::budget::TokenPool;
use crate::cache::CacheConfig;
use crate::provider::ProviderType;
use crate::router::{ProviderRoute, RoutingStrategy};
use crate::server::ServerConfig;

/// Top-level configuration file structure.
#[derive(Debug, Deserialize)]
pub struct HooshConfig {
    #[serde(default)]
    pub server: ServerSection,
    #[serde(default)]
    pub cache: CacheSection,
    #[serde(default)]
    pub providers: Vec<ProviderSection>,
    #[serde(default)]
    pub budgets: Vec<BudgetPoolSection>,
    #[serde(default)]
    pub whisper: WhisperSection,
    #[serde(default)]
    pub tts: TtsSection,
}

#[derive(Debug, Default, Deserialize)]
pub struct WhisperSection {
    /// Path to whisper model file (e.g. "models/ggml-base.en.bin").
    pub model: Option<String>,
}

#[derive(Debug, Default, Deserialize)]
pub struct TtsSection {
    /// URL of the TTS backend (e.g. "http://localhost:5500" for openedai-speech).
    pub url: Option<String>,
}

#[derive(Debug, Deserialize)]
pub struct BudgetPoolSection {
    /// Pool name (e.g. "default", "agent-1").
    pub name: String,
    /// Maximum tokens allowed in this pool.
    pub capacity: u64,
}

#[derive(Debug, Deserialize)]
pub struct ServerSection {
    #[serde(default = "default_bind")]
    pub bind: String,
    #[serde(default = "default_port")]
    pub port: u16,
    #[serde(default)]
    pub strategy: StrategyValue,
}

impl Default for ServerSection {
    fn default() -> Self {
        Self {
            bind: default_bind(),
            port: default_port(),
            strategy: StrategyValue::default(),
        }
    }
}

#[derive(Debug, Default, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum StrategyValue {
    #[default]
    Priority,
    RoundRobin,
    LowestLatency,
    Direct,
}

#[derive(Debug, Deserialize)]
pub struct CacheSection {
    #[serde(default = "default_cache_max")]
    pub max_entries: usize,
    #[serde(default = "default_cache_ttl")]
    pub ttl_secs: u64,
    #[serde(default = "default_true")]
    pub enabled: bool,
}

#[derive(Debug, Deserialize)]
pub struct ProviderSection {
    /// Provider type name (e.g. "ollama", "openai", "anthropic").
    #[serde(rename = "type")]
    pub provider_type: ProviderType,
    /// Base URL. Uses provider-specific default if omitted.
    pub base_url: Option<String>,
    /// API key — literal string or `"$ENV_VAR"` to read from environment.
    pub api_key: Option<String>,
    /// Priority (lower = preferred). Defaults to 10.
    #[serde(default = "default_priority")]
    pub priority: u32,
    /// Model patterns this provider handles.
    #[serde(default)]
    pub models: Vec<String>,
    /// Whether this provider is enabled. Defaults to true.
    #[serde(default = "default_true")]
    pub enabled: bool,
    /// Maximum tokens per request for this provider.
    #[serde(default)]
    pub max_tokens_limit: Option<u32>,
}

fn default_bind() -> String {
    "127.0.0.1".into()
}
fn default_port() -> u16 {
    8088
}
fn default_cache_max() -> usize {
    1000
}
fn default_cache_ttl() -> u64 {
    300
}
fn default_true() -> bool {
    true
}
fn default_priority() -> u32 {
    10
}

impl Default for CacheSection {
    fn default() -> Self {
        Self {
            max_entries: default_cache_max(),
            ttl_secs: default_cache_ttl(),
            enabled: true,
        }
    }
}

/// Resolve an API key value. If it starts with `$`, read from environment.
fn resolve_api_key(raw: &Option<String>) -> Option<String> {
    let raw = raw.as_ref()?;
    if let Some(var_name) = raw.strip_prefix('$') {
        match std::env::var(var_name) {
            Ok(val) => Some(val),
            Err(_) => {
                tracing::warn!(
                    "API key env var ${var_name} is not set — provider will have no API key"
                );
                None
            }
        }
    } else {
        Some(raw.clone())
    }
}

/// Default base URL for a provider type.
fn default_base_url(provider_type: ProviderType) -> &'static str {
    match provider_type {
        ProviderType::Ollama => "http://localhost:11434",
        ProviderType::LlamaCpp => "http://localhost:8080",
        ProviderType::Synapse => "http://localhost:5000",
        ProviderType::LmStudio => "http://localhost:1234",
        ProviderType::LocalAi => "http://localhost:8080",
        ProviderType::OpenAi => "https://api.openai.com",
        ProviderType::Anthropic => "https://api.anthropic.com",
        ProviderType::DeepSeek => "https://api.deepseek.com",
        ProviderType::Mistral => "https://api.mistral.ai",
        ProviderType::Groq => "https://api.groq.com/openai",
        ProviderType::OpenRouter => "https://openrouter.ai/api",
        ProviderType::Google => "https://generativelanguage.googleapis.com",
        ProviderType::Grok => "https://api.x.ai",
        ProviderType::Whisper => "http://localhost:8080",
    }
}

impl HooshConfig {
    /// Load configuration from a TOML file.
    pub fn load(path: impl AsRef<Path>) -> anyhow::Result<Self> {
        let contents = std::fs::read_to_string(path.as_ref())?;
        let config: HooshConfig = toml::from_str(&contents).map_err(|e| {
            // Redact error details that might contain API keys
            let msg = e.to_string();
            if msg.contains("api_key") {
                anyhow::anyhow!("failed to parse config: TOML syntax error near api_key field")
            } else {
                anyhow::anyhow!("failed to parse config: {e}")
            }
        })?;
        Ok(config)
    }

    /// Try loading from `hoosh.toml` in the current directory, or return defaults.
    pub fn load_or_default() -> Self {
        if Path::new("hoosh.toml").exists() {
            match Self::load("hoosh.toml") {
                Ok(config) => {
                    tracing::info!("loaded config from hoosh.toml");
                    config
                }
                Err(e) => {
                    tracing::error!("failed to load hoosh.toml: {e}");
                    std::process::exit(1);
                }
            }
        } else {
            Self {
                server: ServerSection::default(),
                cache: CacheSection::default(),
                providers: Vec::new(),
                budgets: Vec::new(),
                whisper: WhisperSection::default(),
                tts: TtsSection::default(),
            }
        }
    }

    /// Convert to provider routes.
    pub fn routes(&self) -> Vec<ProviderRoute> {
        self.providers
            .iter()
            .map(|p| {
                let base_url = p
                    .base_url
                    .clone()
                    .unwrap_or_else(|| default_base_url(p.provider_type).into());
                ProviderRoute {
                    provider: p.provider_type,
                    priority: p.priority,
                    model_patterns: p.models.clone(),
                    enabled: p.enabled,
                    base_url,
                    api_key: resolve_api_key(&p.api_key),
                    max_tokens_limit: p.max_tokens_limit,
                }
            })
            .collect()
    }

    /// Convert to ServerConfig, merging CLI overrides.
    pub fn into_server_config(
        self,
        bind_override: Option<&str>,
        port_override: Option<u16>,
    ) -> ServerConfig {
        let routes = self.routes();
        let strategy = match self.server.strategy {
            StrategyValue::Priority => RoutingStrategy::Priority,
            StrategyValue::RoundRobin => RoutingStrategy::RoundRobin,
            StrategyValue::LowestLatency => RoutingStrategy::LowestLatency,
            StrategyValue::Direct => RoutingStrategy::Direct,
        };
        let budget_pools = self
            .budgets
            .iter()
            .map(|b| TokenPool::new(&b.name, b.capacity))
            .collect();

        ServerConfig {
            bind: bind_override.map(String::from).unwrap_or(self.server.bind),
            port: port_override.unwrap_or(self.server.port),
            routes,
            strategy,
            cache_config: CacheConfig {
                max_entries: self.cache.max_entries,
                ttl_secs: self.cache.ttl_secs,
                enabled: self.cache.enabled,
            },
            budget_pools,
            whisper_model: self.whisper.model,
            tts_model: self.tts.url,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_minimal_config() {
        let toml = "";
        let config: HooshConfig = toml::from_str(toml).unwrap();
        assert_eq!(config.server.port, 8088);
        assert_eq!(config.server.bind, "127.0.0.1");
        assert!(config.providers.is_empty());
    }

    #[test]
    fn parse_full_config() {
        let toml = r#"
[server]
bind = "0.0.0.0"
port = 9000
strategy = "round_robin"

[cache]
max_entries = 500
ttl_secs = 600
enabled = false

[[providers]]
type = "Ollama"
base_url = "http://gpu-box:11434"
priority = 1
models = ["llama*", "mistral*"]

[[providers]]
type = "OpenAi"
api_key = "$OPENAI_API_KEY"
priority = 10
models = ["gpt-*"]
"#;
        let config: HooshConfig = toml::from_str(toml).unwrap();
        assert_eq!(config.server.port, 9000);
        assert_eq!(config.server.bind, "0.0.0.0");
        assert_eq!(config.cache.max_entries, 500);
        assert!(!config.cache.enabled);
        assert_eq!(config.providers.len(), 2);
        assert_eq!(config.providers[0].provider_type, ProviderType::Ollama);
        assert_eq!(config.providers[1].provider_type, ProviderType::OpenAi);
        assert_eq!(
            config.providers[1].api_key.as_deref(),
            Some("$OPENAI_API_KEY")
        );
    }

    #[test]
    fn routes_from_config() {
        let toml = r#"
[[providers]]
type = "Ollama"
priority = 1
models = ["llama*"]

[[providers]]
type = "OpenAi"
api_key = "sk-test-key"
priority = 5
models = ["gpt-*"]
"#;
        let config: HooshConfig = toml::from_str(toml).unwrap();
        let routes = config.routes();
        assert_eq!(routes.len(), 2);
        assert_eq!(routes[0].base_url, "http://localhost:11434");
        assert!(routes[0].api_key.is_none());
        assert_eq!(routes[1].base_url, "https://api.openai.com");
        assert_eq!(routes[1].api_key.as_deref(), Some("sk-test-key"));
    }

    #[test]
    fn resolve_api_key_literal() {
        let key = Some("sk-literal".into());
        assert_eq!(resolve_api_key(&key).as_deref(), Some("sk-literal"));
    }

    #[test]
    fn resolve_api_key_env_var() {
        // SAFETY: test is single-threaded, no concurrent env access
        unsafe { std::env::set_var("HOOSH_TEST_KEY_1234", "sk-from-env") };
        let key = Some("$HOOSH_TEST_KEY_1234".into());
        assert_eq!(resolve_api_key(&key).as_deref(), Some("sk-from-env"));
        unsafe { std::env::remove_var("HOOSH_TEST_KEY_1234") };
    }

    #[test]
    fn resolve_api_key_missing_env() {
        let key = Some("$HOOSH_NONEXISTENT_KEY_999".into());
        assert!(resolve_api_key(&key).is_none());
    }

    #[test]
    fn resolve_api_key_none() {
        assert!(resolve_api_key(&None).is_none());
    }

    #[test]
    fn default_base_urls() {
        assert_eq!(
            default_base_url(ProviderType::Ollama),
            "http://localhost:11434"
        );
        assert_eq!(
            default_base_url(ProviderType::OpenAi),
            "https://api.openai.com"
        );
        assert_eq!(
            default_base_url(ProviderType::Anthropic),
            "https://api.anthropic.com"
        );
        assert_eq!(
            default_base_url(ProviderType::Groq),
            "https://api.groq.com/openai"
        );
    }

    #[test]
    fn into_server_config_with_overrides() {
        let toml = r#"
[server]
port = 9000
bind = "0.0.0.0"
"#;
        let config: HooshConfig = toml::from_str(toml).unwrap();
